class PackNetAgent(nn.Module):
    def __init__(self, envs, task_id, is_first_task, total_task_num):
        super().__init__()
        self.network = PackNet(
            hidden_dim=512,
            task_id=task_id,
            total_task_num=total_task_num,
            is_first_task=is_first_task,
            layer_init=layer_init,
        )
        self.num_actions = envs.single_action_space.n
        self.actor = layer_init(nn.Linear(512, self.num_actions), std=0.01)
        self.critic = layer_init(nn.Linear(512, 1), std=1)

        self.retrain_mode = False

    def get_value(self, x):
        return self.critic(self.network(x))

    def get_action_and_value(self, x, action=None):
        hidden = self.network(x)
        logits = self.actor(hidden)
        probs = Categorical(logits=logits)
        if action is None:
            action = probs.sample()
        return action, probs.log_prob(action), probs.entropy(), self.critic(hidden)

    def save(self, dirname):
        # un-do the masking for the current task
        self.network.set_view(None)

        os.makedirs(dirname, exist_ok=True)
        torch.save(self, f"{dirname}/packnet.pt")

    def load(
        dirname,
        task_id=None,
        restart_actor_critic=False,
        freeze_bias=True,
        map_location=None,
    ):
        model = torch.load(f"{dirname}/packnet.pt", map_location=map_location)
        model.retrain_mode = False

        if task_id is not None:
            model.network.task_id = task_id

        if restart_actor_critic:
            model.actor = layer_init(nn.Linear(512, model.num_actions), std=0.01)
            model.critic = layer_init(nn.Linear(512, 1), std=1)

        if freeze_bias:
            for name, param in model.network.model.named_parameters():
                if name.endswith(".bias"):
                    param.requires_grad = False
        return model

    def start_retraining(self):
        if self.retrain_mode:
            return  # nothing to do

        print("==> PackNet re-training starts!")

        self.retrain_mode = True
        self.network.prune()  # generate the masks for the current task
        self.network.set_view(self.network.task_id)

    def before_update(self):
        self.network.adjust_gradients(retrain_mode=self.retrain_mode)

class DinoEncoder:
    def __init__(self, dino_size, device):
        # see: https://github.com/facebookresearch/dinov2/blob/main/MODEL_CARD.md#model-details
        if dino_size == "s":
            self.embed_dim = 384
        elif dino_size == "b":
            self.embed_dim = 768
        elif dino_size == "l":
            self.embed_dim = 1024
        elif dino_size == "g":
            self.embed_dim = 1536
        else:
            print(f"Invalid DINOv2 size {dino_size}. Valid values are s, b, l, and g")

        self.dino = torch.hub.load(
            "facebookresearch/dinov2", f"dinov2_vit{dino_size}14_reg"
        ).to(device)
        self.transform = T.Normalize(
            mean=(0.485, 0.456, 0.406), std=(0.229, 0.224, 0.225)
        )

    @torch.no_grad()
    def encode(self, x):
        # x: (batch, n_stack, h, w, n_channels)
        batch_size = x.size(0)
        n_stack = x.size(1)

        x = torch.flatten(
            x, start_dim=0, end_dim=1
        )  # x: (batch * n_stack, h, w, n_channels)
        x = x.permute(0, 3, 1, 2)  # x: (batch * n_stack, n_channles, h, w)

        x = self.transform(x)  # normalize
        latent = self.dino(x)
        latent = latent.resize(batch_size, self.embed_dim * n_stack)

        return latent

